import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import background from "../assets/background.png";
import axios from "axios";

const Form = () => {
  const [email, setEmail] = useState("");
  const [image, setImage] = useState(null);
  const [imageUrl, setImageUrl] = useState("");
  const [option, setOption] = useState("");
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!image) return alert("Please upload an image!");
    try {
      const formData = new FormData();
      formData.append("file", image);

      const response = await axios.post(
        "http://localhost:8000/predict/",
        formData,
        {
          headers: { "Content-Type": "multipart/form-data" },
        }
      );

      // ✅ Pass option to determine whether to show shape
      navigate("/result", {
        state: {
          gem_prediction: response.data.gem.label,
          gem_confidence: response.data.gem.confidence,
          shape_prediction: response.data.shape.label,
          shape_confidence: response.data.shape.confidence,
          image: formData.get("file"),
          show_shape: option === "yes",
        },
      });
    } catch (error) {
      console.error("Error submitting form:", error);
      alert("Prediction failed. Please try again.");
    }
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    setImageUrl(URL.createObjectURL(file));
  };

  // ... imports & logic same as your original ...

return (
  <>
    <Topnav />

    <div className="min-h-screen bg-[#0a1425] py-16 px-6">
      <div className="max-w-3xl mx-auto">
        <h1 className="text-4xl md:text-5xl font-bold text-center text-[#60a5fa] mb-4">
          Gem Analysis
        </h1>
        <p className="text-center text-[#94a3b8] text-lg mb-12">
          Upload a clear photo of your gemstone for instant AI identification
        </p>

        <form
          onSubmit={handleSubmit}
          className="bg-[#111d38]/80 backdrop-blur-md border border-[#1e40af]/40 rounded-2xl p-8 md:p-10 shadow-2xl shadow-black/50"
        >
          {/* Email */}
          <div className="mb-8">
            <label className="block text-[#94a3b8] font-medium mb-2">Email (optional for report)</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-[#0a1425] border border-[#1e40af]/50 text-white rounded-lg px-5 py-3 focus:ring-2 focus:ring-[#60a5fa]/50 focus:border-[#60a5fa] outline-none"
              placeholder="your@email.com"
            />
          </div>

          {/* Upload */}
          <div className="mb-8">
            <label className="block text-[#94a3b8] font-medium mb-2">Gem Photo</label>
            <div className="border-2 border-dashed border-[#1e40af]/50 rounded-xl p-10 text-center hover:border-[#60a5fa]/70 transition">
              <input type="file" accept="image/*" onChange={handleImageChange} className="hidden" id="upload" />
              <label htmlFor="upload" className="cursor-pointer">
                <div className="text-[#60a5fa] text-6xl mb-4">+</div>
                <p className="text-[#94a3b8] font-medium">Click or drag image here</p>
                <p className="text-sm text-[#64748b] mt-2">PNG / JPG • min 126px</p>
              </label>
            </div>

            {imageUrl && (
              <div className="mt-6 rounded-xl overflow-hidden border border-[#1e40af]/40 shadow-xl">
                <img src={imageUrl} alt="Preview" className="w-full max-h-72 object-contain" />
              </div>
            )}
          </div>

          {/* Shape radio */}
          <div className="mb-8">
            <label className="block text-[#94a3b8] font-medium mb-3">
              Identify gem cut / shape?
            </label>
            <div className="flex gap-8">
              <label className="flex items-center gap-2">
                <input type="radio" value="yes" checked={option === "yes"} onChange={() => setOption("yes")} className="w-5 h-5 accent-[#3b82f6]" />
                <span className="text-[#e2e8f0]">Yes</span>
              </label>
              <label className="flex items-center gap-2">
                <input type="radio" value="no" checked={option === "no"} onChange={() => setOption("no")} className="w-5 h-5 accent-[#3b82f6]" />
                <span className="text-[#e2e8f0]">No</span>
              </label>
            </div>
          </div>

          <button
            type="submit"
            disabled={!image}
            className={`w-full py-4 text-lg font-semibold rounded-full transition-all ${
              image
                ? "bg-[#3b82f6] hover:bg-[#2563eb] shadow-lg shadow-[#3b82f6]/40 hover:shadow-xl hover:shadow-[#3b82f6]/60"
                : "bg-[#1e40af]/40 text-[#64748b] cursor-not-allowed"
            }`}
          >
            Analyze Gem
          </button>
        </form>
      </div>
    </div>

    <Footer />
  </>
);
};

export default Form;
